{
  "title": "मूव सेमेंटिक्स की मूल बातें",
  "group": "स्वामित्व",
  "options": [
    {
      "text": "नमस्ते, !",
      "hint": "'philosopher' को मूव करने के बाद क्या होता है, इस पर विचार करें"
    },
    {
      "text": "नमस्ते, सिटियम के ज़ेनो!",
      "hint": "किसी वैल्यू को मूव करने के बाद, क्या हम उसका उपयोग कर सकते हैं?"
    },
    {
      "text": "नमस्ते, एलिया के ज़ेनो!",
      "hint": "स्ट्रिंग में 'Citium' है, 'Elea' नहीं"
    },
    {
      "text": "नमस्ते, मार्कस ऑरेलियस",
      "hint": "जाँचें कि क्या यह स्ट्रिंग की सामग्री से मेल खाता है"
    },
    {
      "text": "कंपाइलेशन एरर: मूव के बाद वैल्यू बॉरो की गई"
    },
    {
      "text": "रनटाइम एरर: नल पॉइंटर एक्सेप्शन",
      "hint": "Rust इन समस्याओं को कंपाइल टाइम पर ही पकड़ लेता है"
    }
  ],
  "questionProse": [
    "इस कोड को चलाने पर क्या होगा? आउटपुट या एरर का अनुमान लगाने की कोशिश करें:"
  ],
  "explanationProse": [
    "यह कोड Rust के ओनरशिप नियमों के कारण कंपाइल नहीं होता। जब हम `philosopher` को `greeting` में असाइन करते हैं, तो String का ओनरशिप `greeting` को मूव हो जाता है। इस मूव के बाद, `philosopher` अब उपयोग के लिए अमान्य हो जाता है।\n\n      इसे ठीक करने के तीन तरीके हैं:\n\n      1. स्ट्रिंग को क्लोन करें (यह एक नई कॉपी बनाता है):",
    "2. एक रेफरेंस का उपयोग करें (वैल्यू को बॉरो करता है):",
    "3. एक स्ट्रिंग स्लाइस का उपयोग करें (स्ट्रिंग के हिस्से को बॉरो करता है):",
    "हर समाधान के अलग-अलग यूज़ केस और परफॉर्मेंस इम्प्लिकेशन्स होते हैं। क्लोनिंग थोड़ी महंगी है लेकिन आपको ओनरशिप देती है, जबकि रेफरेंस हल्के होते हैं लेकिन इन पर लाइफटाइम की पाबंदियाँ लागू होती हैं।"
  ]
}
